FunContAtAdd {f g : ℝ → ℝ} {c : ℝ}
    (hf : FunContAt f c) (hg : FunContAt g c) :
    FunContAt (fun x ↦ f x + g x) c

Lecture20:4.statement:
SeqLim_of_FunLimAt {f : ℝ → ℝ} {L c : ℝ}
    (hf : FunLimAt f L c) :
    ∀ x : ℕ → ℝ, (∀ n, x n ≠ c) → SeqLim x c → SeqLim (fun n ↦ f (x n)) L

Lecture21:1.statement:
FunLim_of_SeqLim {f : ℝ → ℝ} {L c : ℝ}
    (h : ∀ x : ℕ → ℝ, (∀ n, x n ≠ c) → SeqLim x c → SeqLim (fun n ↦ f (x n)) L) :
    FunLimAt f L c

Lecture25:1.statement:
Integrable_of_UnifConv {f : ℕ → ℝ → ℝ} {F : ℝ → ℝ}
    {a b : ℝ} (hab : a < b)
    {ℓ : ℕ → ℝ}
    (hfint : ∀ n, HasIntegral (f n) a b (ℓ n))
    (hfF : UnifConv f F) :
    ∃ (L : ℝ), SeqLim ℓ L ∧ HasIntegral F a b L
